import { IMessageDataWrapper, IMessageParser } from "@nitrots/nitro-renderer";

export interface AchievementRow
{
id: number;
key: string;
name: string;
current: number;
target: number;
xpReward: number;
badgeUrl: string;
description: string;

groupKey: string;
groupOrder: number;
levelOrder: number;
}

export class ProfileAchievementsParser implements IMessageParser
{
private _userId: number = 0;
private _achievements: AchievementRow[] = [];

public flush(): boolean
{
this._userId = 0;
this._achievements = [];
return true;
}

public parse(wrapper: IMessageDataWrapper): boolean
{
// ✅ NEW: first int is the userId this packet belongs to
const userId = wrapper.readInt();
const total = wrapper.readInt();

const rows: AchievementRow[] = [];

for (let i = 0; i < total; i++)
{
const id = wrapper.readInt();
const key = wrapper.readString();
const name = wrapper.readString();
const current = wrapper.readInt();
const target = wrapper.readInt();
const xpReward = wrapper.readInt();
const badgeUrl = wrapper.readString();
const description = wrapper.readString();

const groupKey = wrapper.readString();
const groupOrder = wrapper.readInt();
const levelOrder = wrapper.readInt();

rows.push({
id,
key,
name,
current,
target,
xpReward,
badgeUrl,
description,
groupKey,
groupOrder,
levelOrder
});
}

this._userId = userId;
this._achievements = rows;

// ✅ Dispatch with userId so UI can filter by viewedUserId
window.dispatchEvent(new CustomEvent("profile_achievements_update", {
detail: { userId, achievements: rows }
}));

return true;
}

public get userId(): number
{
return this._userId;
}

public get achievements(): AchievementRow[]
{
return this._achievements;
}
}
